code = """import json
import pandas as pd
import re

reviews = var_call_CVXyQADuDETogcFa6wlnJYFJ
books_path = var_call_o3hzyiiM31zPTGwOMAPlJIwI

with open(books_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# DataFrames
df_rev = pd.DataFrame(reviews)
df_books = pd.DataFrame(books)

# extract numeric suffix after underscore
def extract_num(s):
    if s is None:
        return None
    m = re.search(r"_(\d+)$", str(s))
    return m.group(1) if m else None

df_rev['id_num'] = df_rev['purchase_id'].apply(extract_num)
df_books['id_num'] = df_books['book_id'].apply(extract_num)

# convert types
try:
    df_rev['avg_rating'] = df_rev['avg_rating'].astype(float)
except Exception:
    df_rev['avg_rating'] = df_rev['avg_rating'].apply(lambda x: float(x) if x is not None else None)

df_rev['review_count'] = df_rev['review_count'].astype(int)

# merge
df_merged = pd.merge(df_books, df_rev, on='id_num', how='inner')

# filters
mask_cat = df_merged['categories'].fillna('').str.contains('Literature & Fiction', case=False, na=False)
mask_lang = df_merged['details'].fillna('').str.contains('English', case=False, na=False)
mask_rating = df_merged['avg_rating'] == 5.0

df_final = df_merged[mask_cat & mask_lang & mask_rating]

output = []
for _, row in df_final.iterrows():
    output.append({
        'title': row.get('title'),
        'author': row.get('author'),
        'book_id': row.get('book_id'),
        'purchase_id': row.get('purchase_id'),
        'avg_rating': float(row.get('avg_rating')) if row.get('avg_rating') is not None else None,
        'review_count': int(row.get('review_count')) if row.get('review_count') is not None else None,
        'categories': row.get('categories'),
        'details': row.get('details')
    })

output = sorted(output, key=lambda x: (x['title'] or ''))

print("__RESULT__:")
print(json.dumps(output))"""

